using System;
using _Code.Scripts.Character;
using _Code.Scripts.CheckPoint;
using UnityEngine;
using UnityEngine.SceneManagement;
using UnityEngine.EventSystems;
using _Code.Scripts.UI;

namespace _Code.Scripts.Gameplay
{
    public class GameManager : MonoBehaviour
    {

        public static Action OnPlayerRespawn;

        [SerializeField] 
        private GameplayParameters parameters;
        public static GameManager Instance;

        private GameObject _deathMenu;
        private bool _isDeathMenuActive = false;

        void Awake()
        {
            if (Instance != null && Instance != this)
            {
                Destroy(gameObject);
                return;
            }
            Instance = this;
            DontDestroyOnLoad(gameObject);
        }

        private void OnEnable()
        {
            Player.OnPlayerDied += ShowDeathMenu;
        }

        private void OnDisable()
        {
            Player.OnPlayerDied -= ShowDeathMenu;
        }

        private void Update()
        {
            // Keep EventSystem updating even when timeScale = 0 for UI input to work
            if (_isDeathMenuActive && EventSystem.current != null)
            {
                EventSystem.current.Update();
            }
        }

        public void StartGame()
        {
            SceneManager.LoadScene("LevelPrototype2");
            SceneManager.LoadSceneAsync("LevelPrototype2LW", LoadSceneMode.Additive);
            SceneManager.LoadSceneAsync("LevelPrototype2RW", LoadSceneMode.Additive);
            Time.timeScale = 1f;
            Cursor.lockState = CursorLockMode.Locked;
            Cursor.visible = false;
        }

        public void ReturnToMenu()
        {
            _deathMenu = null;
            SceneManager.LoadScene("MainMenu");
        }

        public void RegisterDeathMenu(GameObject deathMenu)
        {
            _deathMenu = deathMenu;
            Debug.Log($"DeathMenu registered: {deathMenu?.name}");
        }

        private void ShowDeathMenu()
        {
            _deathMenu?.SetActive(true);
            Time.timeScale = 0f;
            Cursor.lockState = CursorLockMode.None;
            Cursor.visible = true;
            Debug.Log($"ShowDeathMenu: menu is now {(_deathMenu?.activeSelf == true ? "ACTIVE" : "INACTIVE")}, TimeScale={Time.timeScale}");
        }

        public void RespawnPlayer()
        {
            OnPlayerRespawn?.Invoke();
            Checkpoint.RespawnPlayer();
            Time.timeScale = 1f;
            Cursor.lockState = CursorLockMode.Locked;
            Cursor.visible = false;
        }
    }
}

using System;
using _Code.Scripts.Character;
using _Code.Scripts.CheckPoint;
using UnityEngine;
using UnityEngine.SceneManagement;
using UnityEngine.EventSystems;
using _Code.Scripts.UI;

namespace _Code.Scripts.Gameplay
{
    public class GameManager : MonoBehaviour
    {

        public static Action OnPlayerRespawn;

        [SerializeField] 
        private GameplayParameters parameters;
        public static GameManager Instance;

        private GameObject _deathMenu;
        private bool _isDeathMenuActive = false;

        void Awake()
        {
            if (Instance != null && Instance != this)
            {
                Destroy(gameObject);
                return;
            }
            Instance = this;
            DontDestroyOnLoad(gameObject);
        }

        private void OnEnable()
        {
            Player.OnPlayerDied += ShowDeathMenu;
        }

        private void OnDisable()
        {
            Player.OnPlayerDied -= ShowDeathMenu;
        }

        private void Update()
        {
            // Keep EventSystem updating even when timeScale = 0 for UI input to work
            if (_isDeathMenuActive && EventSystem.current != null)
            {
                EventSystem.current.Update();
            }
        }

        public void StartGame()
        {
            SceneManager.LoadScene("LevelPrototype2");
            SceneManager.LoadSceneAsync("LevelPrototype2LW", LoadSceneMode.Additive);
            SceneManager.LoadSceneAsync("LevelPrototype2RW", LoadSceneMode.Additive);
            Time.timeScale = 1f;
            Cursor.lockState = CursorLockMode.Locked;
            Cursor.visible = false;
        }

        public void ReturnToMenu()
        {
            _deathMenu = null;
            SceneManager.LoadScene("MainMenu");
        }

        public void RegisterDeathMenu(GameObject deathMenu)
        {
            _deathMenu = deathMenu;
            Debug.Log($"DeathMenu registered: {deathMenu?.name}");
        }

        private void ShowDeathMenu()
        {
            _deathMenu?.SetActive(true);
            _isDeathMenuActive = true;
            Time.timeScale = 0f;
            Cursor.lockState = CursorLockMode.None;
            Cursor.visible = true;
            Debug.Log($"ShowDeathMenu: menu is now {(_deathMenu?.activeSelf == true ? "ACTIVE" : "INACTIVE")}, TimeScale={Time.timeScale}");
        }

        public void RespawnPlayer()
        {
            _isDeathMenuActive = false;
            OnPlayerRespawn?.Invoke();
            Checkpoint.RespawnPlayer();
            Time.timeScale = 1f;
            Cursor.lockState = CursorLockMode.Locked;
            Cursor.visible = false;
        }
    }
}
